            command: `FILE_PATH=$(node -e "try{console.log(JSON.parse(require('fs').readFileSync(0,'utf8')).tool_input?.file_path||'')}catch{console.log('')}") && [ -n "$FILE_PATH" ] && echo "$FILE_PATH" | grep -qE "androidTest/.*\\.kt$" && grep -cE "\\bThread\\.sleep\\(|SystemClock\\.sleep\\(" "$FILE_PATH" | grep -v "^0$" > /dev/null 2>&1 && { echo "Thread.sleep() or SystemClock.sleep() detected in Espresso test \u2014 use IdlingResource for async synchronization instead" >&2; exit 2; } || exit 0`,
