async function findUniversalFiles(targetDir, pluginPath) {
  const targets = [];
  const agentsPath = agentsDir(targetDir);
  for (const name of UNIVERSAL_AGENT_NAMES) {
    const filePath = path28.join(agentsPath, `${name}.md`);
    if (await fileExists(filePath)) {
      const modified = pluginPath ? await isModifiedFromPlugin(filePath, path28.join(pluginPath, "agents", `${name}.md`)) : false;
      targets.push({
        path: filePath,
        relativePath: path28.relative(targetDir, filePath),
        type: "agent",
        isDirectory: false,
        modified
      });
    }
  }
  const skillsPath = skillsDir(targetDir);
  for (const name of UNIVERSAL_SKILL_NAMES) {
    const dirPath = path28.join(skillsPath, name);
    if (await fileExists(dirPath)) {
      const skillFile = path28.join(dirPath, "SKILL.md");
      const modified = pluginPath ? await isModifiedFromPlugin(skillFile, path28.join(pluginPath, "skills", name, "SKILL.md")) : false;
      targets.push({
        path: dirPath,
        relativePath: path28.relative(targetDir, dirPath) + "/",
        type: "skill",
        isDirectory: true,
        modified
      });
    }
  }
  const hooksPath = hooksDir(targetDir);
  for (const filename of UNIVERSAL_HOOK_SCRIPT_FILENAMES) {
    const filePath = path28.join(hooksPath, filename);
    if (await fileExists(filePath)) {
      const modified = pluginPath ? await isModifiedFromPlugin(filePath, path28.join(pluginPath, "hooks", "scripts", filename)) : false;
      targets.push({
        path: filePath,
        relativePath: path28.relative(targetDir, filePath),
        type: "hook-script",
        isDirectory: false,
        modified
      });
    }
  }
  return targets;
}
async function isModifiedFromPlugin(projectFile, pluginFile) {
  const projectContent = await readFileOrNull(projectFile);
  const pluginContent = await readFileOrNull(pluginFile);
  if (!projectContent || !pluginContent) return false;
  return projectContent.replace(/\r\n/g, "\n").trim() !== pluginContent.replace(/\r\n/g, "\n").trim();
}
async function cleanSettingsHooks(targetDir, dryRun) {
  const settingsPath = path28.join(targetDir, CLAUDE_DIR, SETTINGS_FILE);
  const content = await readFileOrNull(settingsPath);
  if (!content) return false;
  let settings;
  try {
    settings = JSON.parse(content);
  } catch {
    return false;
  }
  const hooks = settings.hooks;
  if (!hooks || typeof hooks !== "object") return false;
  let modified = false;
  for (const [event, entries] of Object.entries(hooks)) {
    if (!Array.isArray(entries)) continue;
    const filtered = entries.filter((entry) => {
      if (typeof entry !== "object" || entry === null) return true;
      const e = entry;
      if ("hooks" in e && Array.isArray(e.hooks)) {
        const filteredHooks = e.hooks.filter(
          (h) => typeof h.command !== "string" || !isUniversalHookCommand(h.command)
        );
        if (filteredHooks.length === 0) return false;
        if (filteredHooks.length < e.hooks.length) {
          e.hooks = filteredHooks;
          modified = true;
        }
        return true;
      }
      if ("command" in e && typeof e.command === "string") {
        if (isUniversalHookCommand(e.command)) return false;
      }
      return true;
    });
    if (filtered.length !== entries.length) {
      modified = true;
      if (filtered.length === 0) {
        delete hooks[event];
      } else {
        hooks[event] = filtered;
      }
    }
  }
  if (Object.keys(hooks).length === 0) {
    delete settings.hooks;
    modified = true;
  }
  if (modified && !dryRun) {
    await fs5.writeFile(settingsPath, JSON.stringify(settings, null, 2) + "\n");
  }
  return modified;
}
async function performCleanup(opts) {
  const { targetDir, force = false, dryRun = false } = opts;
  const pluginPath = detectPluginInstalled(targetDir);
  if (!pluginPath && !force) {
    return { cleaned: false, removed: [], skipped: [], settingsClean: false };
  }
  const targets = await findUniversalFiles(targetDir, pluginPath);
  const identical = targets.filter((t) => !t.modified);
  const modified = targets.filter((t) => t.modified);
  const toRemove = force ? targets : identical;
  const settingsClean = await cleanSettingsHooks(targetDir, true);
  if (toRemove.length === 0 && !settingsClean) {
    return {
      cleaned: false,
      removed: [],
      skipped: modified.map((t) => t.relativePath),
      settingsClean: false
    };
  }
  const removed = toRemove.map((t) => t.relativePath);
  if (!dryRun) {
    for (const target of toRemove) {
      if (target.isDirectory) {
        await fs5.rm(target.path, { recursive: true });
      } else {
        await fs5.unlink(target.path);
      }
    }
    if (settingsClean) {
      await cleanSettingsHooks(targetDir, false);
    }
  }
  return {
    cleaned: removed.length > 0 || settingsClean,
    removed,
    skipped: force ? [] : modified.map((t) => t.relativePath),
    settingsClean
  };
}

