import fs6 from "fs/promises";
import path29 from "path";
async function performEject(opts) {
  const { targetDir } = opts;
  const filesToRemove = [
    path29.join(targetDir, META_FILE)
  ];
  const dirsToRemove = [
    path29.join(targetDir, BACKUP_DIR),
    path29.join(targetDir, KNOWLEDGE_CACHE_DIR)
  ];
  const removed = [];
  for (const file2 of filesToRemove) {
    if (await fileExists(file2)) {
      await fs6.unlink(file2);
      removed.push(path29.relative(targetDir, file2));
    }
  }
  for (const dir of dirsToRemove) {
    if (await fileExists(dir)) {
      await fs6.rm(dir, { recursive: true });
      removed.push(path29.relative(targetDir, dir) + "/");
    }
  }
  return { ejected: removed.length > 0, removed };
}

