async function checkHookScripts(pluginDir) {
  const hooksJsonPath = path32.join(pluginDir, "hooks", "hooks.json");
  const content = await readJsonOrNull(hooksJsonPath);
  if (!content) {
    return {
      check: "hook-scripts",
      status: "unhealthy",
      message: "No se puede validar scripts: hooks.json no disponible",
      autoFixable: true
    };
  }
  const missing = [];
  for (const eventValue of Object.values(content)) {
    const entries = extractEntries(eventValue);
    for (const entry of entries) {
      const scriptPath = extractScriptPath(entry.command, pluginDir);
      if (scriptPath && !await fileExists(scriptPath)) {
        missing.push(path32.basename(scriptPath));
      }
    }
  }
  if (missing.length > 0) {
    return {
      check: "hook-scripts",
      status: "unhealthy",
      message: `Scripts faltantes: ${missing.join(", ")}`,
      autoFixable: true
    };
  }
  return {
    check: "hook-scripts",
    status: "healthy",
    message: "Todos los hook scripts existen",
    autoFixable: false
  };
}
function extractEntries(value) {
  if (Array.isArray(value)) return value;
  const all = [];
  for (const arr of Object.values(value)) {
    if (Array.isArray(arr)) all.push(...arr);
  }
  return all;
}
function extractScriptPath(command, pluginDir) {
  const match = command.match(/\$\{CLAUDE_PLUGIN_ROOT\}\/(.+)/);
  if (match?.[1]) {
    return path32.join(pluginDir, match[1].replace(/\//g, path32.sep));
  }
  return null;
}

