// src/learning/error-analyzer.ts
var CLASSIFIERS = [
  {
    match: /permission denied/i,
    category: "tool-error",
    confidence: 80,
    descriptionFn: () => "Permission denied \u2014 archivo o directorio no accesible"
  },
  {
    match: /EACCES/i,
    category: "tool-error",
    confidence: 80,
    descriptionFn: () => "EACCES \u2014 permisos insuficientes en filesystem"
  },
  {
    match: /cannot find module ['"]([^'"]+)['"]/i,
    category: "code-pattern",
    confidence: 70,
    descriptionFn: (m) => `M\xF3dulo no encontrado: ${m[1] ?? "unknown"}`
  },
  {
    match: /Module not found/i,
    category: "code-pattern",
    confidence: 70,
    descriptionFn: () => "M\xF3dulo no encontrado"
  },
  {
    match: /(TS\d{4}):/,
    category: "code-pattern",
    confidence: 60,
    descriptionFn: (m) => `Error TypeScript ${m[1]}`
  },
  {
    match: /SyntaxError/i,
    category: "code-pattern",
    confidence: 65,
    descriptionFn: () => "Error de sintaxis"
  },
  {
    match: /hook.*fail|hook.*error/i,
    category: "hook-failure",
    confidence: 85,
    descriptionFn: () => "Hook script fall\xF3"
  },
  {
    match: /FAIL|AssertionError|AssertionFailedError/i,
    category: "code-pattern",
    confidence: 50,
    descriptionFn: () => "Test assertion fallido"
  },
  {
    match: /ENOENT/i,
    category: "tool-error",
    confidence: 70,
    descriptionFn: () => "Archivo o directorio no encontrado (ENOENT)"
  },
  {
    match: /timeout|ETIMEDOUT/i,
    category: "tool-error",
    confidence: 60,
    descriptionFn: () => "Operaci\xF3n timeout"
  },
  {
    match: /JSON\.parse|Unexpected token|is not valid JSON/i,
    category: "config-issue",
    confidence: 75,
    descriptionFn: () => "JSON inv\xE1lido en archivo de configuraci\xF3n"
  },
  // Process-level classifiers (CI/release errors)
  {
    match: /plugin\.json.*version.*mismatch|plugin.*stale|build:plugin/i,
    category: "config-issue",
    confidence: 80,
    descriptionFn: () => "Plugin build stale \u2014 versiones desincronizadas"
  },
  {
    match: /UNIVERSAL_\w+_NAMES|constant.*mismatch|agent.*not.*found.*in.*set/i,
    category: "code-pattern",
    confidence: 75,
    descriptionFn: () => "Inconsistencia de constantes \u2014 UNIVERSAL_* desactualizado"
  },
  {
    match: /CI.*fail|workflow.*fail|GitHub.*Actions.*error|pipeline.*error/i,
    category: "tool-error",
    confidence: 70,
    descriptionFn: () => "Fallo de pipeline CI detectado"
  }
];
function classifyError(errorMessage, tool) {
  for (const classifier of CLASSIFIERS) {
    const match = errorMessage.match(classifier.match);
    if (match) {
      return {
        category: classifier.category,
        confidence: classifier.confidence,
        matchPattern: classifier.match.source,
        description: classifier.descriptionFn(match),
        tool
      };
    }
  }
  return {
    category: "tool-error",
    confidence: 30,
    matchPattern: "unclassified",
    description: `Error no clasificado: ${errorMessage.slice(0, 80)}`,
    tool
  };
}
function classifyErrors(errors) {
  const results = [];
  for (const error49 of errors) {
    const classification = classifyError(error49.message, error49.tool);
    if (classification) {
      results.push(classification);
    }
  }
  return results;
}

// src/learning/pattern-matcher.ts
function matchAndUpdatePatterns(store, classifications) {
  const updated = [];
  for (const classification of classifications) {
    const pattern = addErrorPattern(store, {
      category: classification.category,
      tool: classification.tool,
      matchPattern: classification.matchPattern,
      description: classification.description
    });
    updated.push(pattern);
  }
  return updated;
}
function findPatternsForRuleGeneration(store, threshold) {
  return store.errorPatterns.filter(
    (p) => p.occurrences >= threshold && !p.ruleGenerated
  );
}

// src/learning/rule-generator.ts
import path39 from "path";
async function generateRuleFromPattern(projectRoot, pattern) {
  const filename = `${pattern.id}.md`;
  const filePath = path39.join(projectRoot, CLAUDE_DIR, RULES_DIR, "learned", filename);
  const content = formatRuleContent(pattern);
  await writeFileAtomic(filePath, content);
  return filePath;
}
function formatRuleContent(pattern) {
  const lines = [];
  lines.push("---");
  lines.push(`description: "Auto-generated rule from error pattern: ${pattern.description}"`);
  lines.push(`globs: "**/*"`);
  lines.push("---");
  lines.push("");
  lines.push(`# ${pattern.description}`);
  lines.push("");
  lines.push(`> Auto-generated by diverger-claude from ${pattern.occurrences} occurrences of this error pattern.`);
  lines.push("");
  lines.push("## Problem");
  lines.push("");
  lines.push(`This error has been observed ${pattern.occurrences} times (category: \`${pattern.category}\`${pattern.tool ? `, tool: \`${pattern.tool}\`` : ""}).`);
  lines.push("");
  lines.push(`Pattern: \`${pattern.matchPattern}\``);
  lines.push("");
  if (pattern.resolution) {
    lines.push("## Resolution");
    lines.push("");
    lines.push(pattern.resolution);
    lines.push("");
  }
  lines.push("## Stats");
  lines.push("");
  lines.push(`- First seen: ${pattern.firstSeen}`);
  lines.push(`- Last seen: ${pattern.lastSeen}`);
  lines.push(`- Occurrences: ${pattern.occurrences}`);
  lines.push("");
  return lines.join("\n");
}

// src/learning/session-extractor.ts
async function extractSessionLearnings(projectRoot, store, errors) {
  if (errors.length === 0) {
    return { errorsProcessed: 0, patternsUpdated: 0, rulesGenerated: 0, generatedRulePaths: [] };
  }
  const classifications = classifyErrors(
    errors.map((e) => ({ message: e.message, tool: e.tool }))
  );
  const updatedPatterns = matchAndUpdatePatterns(store, classifications);
  const rulePatterns = findPatternsForRuleGeneration(store, ERROR_PATTERN_RULE_THRESHOLD);
  const generatedRulePaths = [];
  for (const pattern of rulePatterns) {
    try {
      const rulePath = await generateRuleFromPattern(projectRoot, pattern);
      pattern.ruleGenerated = true;
      store.stats.rulesGenerated = (store.stats.rulesGenerated ?? 0) + 1;
      generatedRulePaths.push(rulePath);
    } catch {
    }
  }
  return {
    errorsProcessed: errors.length,
    patternsUpdated: updatedPatterns.length,
    rulesGenerated: generatedRulePaths.length,
    generatedRulePaths
  };
}

// src/learning/index.ts
var LearningEngine = class {
  projectRoot;
  constructor(projectRoot) {
    this.projectRoot = projectRoot;
  }
  /**
   * Process errors from a session and extract learnings.
   */
  async processSessionErrors(errors) {
    const store = await loadProjectMemory(this.projectRoot);
    const result = await extractSessionLearnings(this.projectRoot, store, errors);
    await saveProjectMemory(this.projectRoot, store);
    return result;
  }
  /**
   * Get the memory store (for inspection).
   */
  async getStore() {
    return loadProjectMemory(this.projectRoot);
  }
};

