// src/learning/ci-error-parser.ts
function parseGitHubActionsLog(logOutput) {
  const errors = [];
  const lines = logOutput.split("\n").filter((l) => l.trim());
  for (const line of lines) {
    const parts = line.split("	");
    let jobName = "unknown";
    let step;
    let message = line;
    if (parts.length >= 3) {
      jobName = parts[0].trim();
      step = parts[1].trim();
      message = parts.slice(2).join("	").trim();
    } else if (parts.length === 2) {
      jobName = parts[0].trim();
      message = parts[1].trim();
    }
    const stripped = stripAnsi(message);
    if (isErrorLine(stripped)) {
      errors.push({
        source: "github-actions",
        jobName,
        step: step ?? void 0,
        message: cleanErrorMessage(stripped)
      });
    }
  }
  return { errors, conclusion: errors.length > 0 ? "failure" : "success" };
}
function parseGitLabCILog(logOutput) {
  const errors = [];
  const lines = logOutput.split("\n");
  let currentJob = "unknown";
  for (const line of lines) {
    const trimmed = line.trim();
    const jobMatch = trimmed.match(/section_start:\d+:(\S+)/);
    if (jobMatch) {
      currentJob = jobMatch[1];
      continue;
    }
    const jobHeaderMatch = trimmed.match(/^Running on (.+) via/);
    if (jobHeaderMatch) continue;
    const strippedLine = stripAnsi(trimmed);
    if (isErrorLine(strippedLine)) {
      errors.push({
        source: "gitlab-ci",
        jobName: currentJob,
        message: cleanErrorMessage(strippedLine)
      });
    }
    const exitMatch = trimmed.match(/exit(?:ed)?\s+(?:with\s+)?(?:code\s+)?(\d+)/i);
    if (exitMatch && exitMatch[1] !== "0") {
      errors.push({
        source: "gitlab-ci",
        jobName: currentJob,
        message: `Process exited with code ${exitMatch[1]}`,
        exitCode: parseInt(exitMatch[1], 10)
      });
    }
  }
  return { errors, conclusion: errors.length > 0 ? "failure" : "success" };
}
function ciErrorsToSessionErrors(entries) {
  return entries.map((entry) => ({
    message: `[CI:${entry.source}/${entry.jobName}] ${entry.message}`,
    tool: "ci-pipeline",
    timestamp: entry.timestamp ?? (/* @__PURE__ */ new Date()).toISOString()
  }));
}
function isErrorLine(line) {
  const errorPatterns = [
    /^##\[error\]/,
    /^Error:/i,
    /^error\s/i,
    /^FAIL\b/i,
    /error TS\d+/,
    /ENOENT|EACCES|EPERM/,
    /npm ERR!/,
    /ERR_/,
    /AssertionError|AssertionFailedError/i,
    /SyntaxError/,
    /TypeError:/,
    /ReferenceError:/,
    /Cannot find module/,
    /command not found/,
    /Permission denied/,
    /version.*mismatch/i,
    /build:plugin/i
  ];
  return errorPatterns.some((p) => p.test(line));
}
function stripAnsi(message) {
  return message.replace(/\u001b\[[0-9;]*m/g, "");
}
function cleanErrorMessage(message) {
  return message.replace(/^##\[error\]\s*/i, "").replace(/^\d{4}-\d{2}-\d{2}T[\d:.Z]+\s*/, "").trim();
}

// src/mcp/tools/ingest-ci-errors.ts
function registerIngestCIErrorsTool(server2) {
  server2.tool(
    "ingest_ci_errors",
    "Ingest errors from CI pipeline (GitHub Actions or GitLab CI) into the learning system",
    {
      projectDir: external_exports3.string().describe("Absolute path to the project root directory"),
      source: external_exports3.enum(["github-actions", "gitlab-ci"]).describe("CI provider type"),
      logContent: external_exports3.string().describe("Raw CI log content (from gh run view --log-failed or GitLab CI job log)")
    },
    async ({ projectDir, source, logContent }) => {
      if (!await fileExists(projectDir)) {
        return {
          content: [{ type: "text", text: JSON.stringify({ error: "DIRECTORY_NOT_FOUND", message: `Directory not found: ${projectDir}` }) }],
          isError: true
        };
      }
      try {
        const parseResult = source === "github-actions" ? parseGitHubActionsLog(logContent) : parseGitLabCILog(logContent);
        if (parseResult.errors.length === 0) {
          return {
            content: [{ type: "text", text: JSON.stringify({
              errorsFound: 0,
              patternsUpdated: 0,
              rulesGenerated: 0,
              message: "No errors found in CI log"
            }) }]
          };
        }
        const sessionErrors = ciErrorsToSessionErrors(parseResult.errors);
        const engine = new LearningEngine(projectDir);
        const result = await engine.processSessionErrors(sessionErrors);
        return {
          content: [{ type: "text", text: JSON.stringify({
            errorsFound: parseResult.errors.length,
            errorsProcessed: result.errorsProcessed,
            patternsUpdated: result.patternsUpdated,
            rulesGenerated: result.rulesGenerated,
            generatedRulePaths: result.generatedRulePaths,
            source,
            conclusion: parseResult.conclusion
          }) }]
        };
      } catch (err) {
        return {
          content: [{ type: "text", text: JSON.stringify({ error: "CI_INGESTION_ERROR", message: extractErrorMessage(err) }) }],
          isError: true
        };
      }
    }
  );
}

